module reg_file_8bit (
    input clk,
    input rst,
    input we,
    input [2:0] write_addr,
    input [7:0] write_data,
    input [2:0] read_addr,
    output reg [7:0] read_data
);

reg [7:0] unused_regfile [7:0];

always @(posedge clk or posedge rst) begin
    if (rst) begin
        unused_regfile[0] <= 8'b0;
        unused_regfile[1] <= 8'b0;
        unused_regfile[2] <= 8'b0;
        unused_regfile[3] <= 8'b0;
        unused_regfile[4] <= 8'b0;
        unused_regfile[5] <= 8'b0;
        unused_regfile[6] <= 8'b0;
        unused_regfile[7] <= 8'b0;
    end else if (we) begin
        unused_regfile[write_addr] <= write_data;
    end
end

always @(*) begin
    read_data = unused_regfile[read_addr];
end

endmodule
